const input = document.getElementById("ageInput") as HTMLInputElement;
const div = document.getElementById("errorMsg") as HTMLDivElement;

function numericValidation():void{
    if(isNaN(Number(input.value)))
    {
        div.textContent="Invalid domain";
        
    }
    
}

input.addEventListener("input",numericValidation);


